const stytch = require('stytch');

const STYTCH_PROJECT_ID = process.env.STYTCH_PROJECT_ID;
const STYTCH_SECRET = process.env.STYTCH_SECRET;

if (!STYTCH_PROJECT_ID || !STYTCH_SECRET) {
  console.error('Missing STYTCH_PROJECT_ID or STYTCH_SECRET environment variables');
  process.exit(1);
}

const client = new stytch.Client({
  project_id: STYTCH_PROJECT_ID,
  secret: STYTCH_SECRET,
  env: stytch.envs.test, // Defaulting to test environment
});

const sessionToken = process.argv[2];

if (!sessionToken) {
  console.error('Usage: node verify_session.js <session_token>');
  process.exit(1);
}

async function authenticateSession() {
  try {
    const response = await client.sessions.authenticate({
      session_token: sessionToken,
    });
    console.log(response.session.user_id);
  } catch (error) {
    console.error('Error authenticating session:', error.message || error);
    process.exit(1);
  }
}

authenticateSession();

